def solve(weight_percent_data, porosity_data, organic_carbon_data):
    if not weight_percent_data or not porosity_data or not organic_carbon_data:
        return None

    volume_percent_data = {}
    total_weight_percent = sum(weight_percent_data.values())

    for mineral, weight_percent in weight_percent_data.items():
        volume_percent_data[mineral] = (weight_percent / total_weight_percent) * (1 - porosity_data) * (1 - organic_carbon_data)

    return volume_percent_data
